import { useState } from "react";
import { loginUser } from "../../api/authApi";

function Login() {

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const handleSubmit =
    async (e) => {

      e.preventDefault();

      try {

        const data =
          await loginUser({
            email,
            password
          });

        alert(
          "Login Successful"
        );

        console.log(data);

      } catch (error) {

        alert(
          error.response?.data?.message ||
          "Login Failed"
        );

      }
    };

  return (
    <div
      style={{
        width: "400px",
        margin: "50px auto"
      }}
    >
      <h2>IQAC Login</h2>

      <form
        onSubmit={
          handleSubmit
        }
      >

        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) =>
            setEmail(
              e.target.value
            )
          }
        />

        <br />
        <br />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) =>
            setPassword(
              e.target.value
            )
          }
        />

        <br />
        <br />

        <button
          type="submit"
        >
          Login
        </button>

      </form>
    </div>
  );
}

export default Login;
